import React from 'react'
import { Link } from 'react-router-dom'

const Links = (props) => {
   const path=props.path
  return (
    <>
      <Link to="/" className={path==="/"?"text-selected-text":""}>Home</Link>
      <Link to="/about" className={path==="/about"?"text-selected-text":""}>About</Link>
      <Link to="/project" className={path==="/project"?"text-selected-text":""}>Project</Link>
      <Link to="/contact"><button className={path==="/contact"?"bg-selected-text px-6 py-2 font-bold":"px-6 py-2 bg-theme font-bold"}>Contact</button></Link>
    </>
  )
}

export default Links
